import React, { useEffect, useRef, useState } from 'react';
import API from '../../api/axios';
import MessageBubble from './MessageBubble';
import TypingIndicator from './TypingIndicator';

export default function ChatBox({ chat, socketRef }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  // Call States
  const [incomingCall, setIncomingCall] = useState(null);
  const [callActive, setCallActive] = useState(false);
  const [isAudioOnly, setIsAudioOnly] = useState(false);

  // File States
  const [selectedFile, setSelectedFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [fileLoading, setFileLoading] = useState(false);

  // WebRTC Refs
  const localVideo = useRef(null);
  const remoteVideo = useRef(null);
  const peerRef = useRef(null);
  const localStreamRef = useRef(null);
  const pendingIceCandidates = useRef([]);

  const typingTimeout = useRef(null);
  const scrollRef = useRef();

  const getMe = () => JSON.parse(localStorage.getItem('user') || 'null');

  const getPartnerId = () => {
    const me = getMe();
    if (!chat || !Array.isArray(chat.users)) return null;
    const partner = chat.users.find(u => {
      const id = typeof u === 'string' ? u : (u._id || u.id);
      return String(id) !== String(me?._id);
    });
    return typeof partner === 'string' ? partner : (partner?._id || partner?.id);
  };

  // --- WebRTC Core Logic ---

  const createPeer = (targetId) => {
    const pc = new RTCPeerConnection({
      iceServers: [{ urls: "stun:stun.l.google.com:19302" }]
    });

    pc.onicecandidate = (event) => {
      if (event.candidate && socketRef.current) {
        socketRef.current.emit("ice_candidate", {
          to: targetId,
          candidate: event.candidate
        });
      }
    };

    pc.ontrack = (event) => {
      if (remoteVideo.current && event.streams[0]) {
        remoteVideo.current.srcObject = event.streams[0];
      }
    };

    return pc;
  };

  const processPendingIceCandidates = async () => {
    if (peerRef.current?.remoteDescription) {
      while (pendingIceCandidates.current.length > 0) {
        const candidate = pendingIceCandidates.current.shift();
        await peerRef.current.addIceCandidate(new RTCIceCandidate(candidate));
      }
    }
  };

  const startCall = async (audioOnly = false) => {
    try {
      const partnerId = getPartnerId();
      if (!partnerId) return;

      setIsAudioOnly(audioOnly);
      const stream = await navigator.mediaDevices.getUserMedia({
        video: !audioOnly,
        audio: true
      });

      localStreamRef.current = stream;
      if (localVideo.current) localVideo.current.srcObject = stream;

      const pc = createPeer(partnerId);
      stream.getTracks().forEach(track => pc.addTrack(track, stream));

      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);

      socketRef.current.emit("call_user", {
        to: partnerId,
        offer,
        from: getMe()?._id,
        isAudioOnly: audioOnly
      });

      peerRef.current = pc;
      setCallActive(true);
    } catch (err) {
      console.error("Start call failed:", err);
    }
  };

  const acceptCall = async () => {
    try {
      const { offer, from, isAudioOnly: incomingAudioOnly } = incomingCall;
      setIsAudioOnly(incomingAudioOnly);

      const stream = await navigator.mediaDevices.getUserMedia({
        video: !incomingAudioOnly,
        audio: true
      });

      localStreamRef.current = stream;
      if (localVideo.current) localVideo.current.srcObject = stream;

      const pc = createPeer(from);
      stream.getTracks().forEach(track => pc.addTrack(track, stream));

      await pc.setRemoteDescription(new RTCSessionDescription(offer));
      await processPendingIceCandidates(); // Handle candidates received before the offer

      const answer = await pc.createAnswer();
      await pc.setLocalDescription(answer);

      socketRef.current.emit("answer_call", { to: from, answer });

      peerRef.current = pc;
      setIncomingCall(null);
      setCallActive(true);
    } catch (err) {
      console.error("Accept call failed:", err);
    }
  };

  const endCall = () => {
    if (peerRef.current) {
      peerRef.current.close();
      peerRef.current = null;
    }
    if (localStreamRef.current) {
      localStreamRef.current.getTracks().forEach(t => t.stop());
      localStreamRef.current = null;
    }
    pendingIceCandidates.current = [];
    setCallActive(false);
    setIncomingCall(null);
  };

  // --- Socket Effects ---

  useEffect(() => {
    const socket = socketRef?.current;
    if (!socket) return;

    socket.on('incoming_call', (data) => setIncomingCall(data));

    socket.on('call_answered', async ({ answer }) => {
      if (peerRef.current) {
        await peerRef.current.setRemoteDescription(new RTCSessionDescription(answer));
        await processPendingIceCandidates();
      }
    });

    socket.on('ice_candidate', async ({ candidate }) => {
      if (peerRef.current?.remoteDescription) {
        await peerRef.current.addIceCandidate(new RTCIceCandidate(candidate));
      } else {
        pendingIceCandidates.current.push(candidate);
      }
    });

    socket.on('call_ended', endCall);

    return () => {
      socket.off('incoming_call');
      socket.off('call_answered');
      socket.off('ice_candidate');
      socket.off('call_ended');
    };
  }, [socketRef]);

  // --- Standard Chat Logic ---

  useEffect(() => {
    const loadMessages = async () => {
      if (!chat) return;
      try {
        const res = await API.get(`/messages/${chat._id}`);
        setMessages(res.data);
        scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
        await API.put('/messages/seen', { chatId: chat._id });
      } catch (err) { console.error(err); }
    };
    loadMessages();
    socketRef.current?.emit('join_chat', chat?._id);
  }, [chat, socketRef]);

  const sendMessage = async () => {
    if (!input.trim() || !chat) return;
    try {
      const res = await API.post('/messages', { content: input, chat: chat._id });
      setMessages(prev => [...prev, res.data]);
      socketRef.current?.emit('new_message', res.data);
      setInput('');
    } catch (err) { console.error(err); }
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', background: '#fff' }}>

      {/* Header / Call Controls */}
      <div style={{ padding: '10px 20px', borderBottom: '1px solid #eee', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <strong>{chat?.chatName || "Chat"}</strong>
        <div style={{ display: 'flex', gap: '10px' }}>
          {!callActive && (
            <>
              <button onClick={() => startCall(false)} style={btnStyle}>📹 Video</button>
              <button onClick={() => startCall(true)} style={btnStyle}>🎧 Audio</button>
            </>
          )}
          {callActive && <button onClick={endCall} style={{ ...btnStyle, background: '#ff4d4d' }}>End Call</button>}
        </div>
      </div>

      {/* Message List */}
      <div style={{ flex: 1, overflowY: 'auto', padding: '20px', background: '#f9f9f9' }}>
        {messages.map((m) => <MessageBubble key={m._id} m={m} />)}
        <div ref={scrollRef} />
      </div>

      {/* Incoming Call Overlay */}
      {incomingCall && !callActive && (
        <div style={overlayStyle}>
          <p>Incoming {incomingCall.isAudioOnly ? 'Audio' : 'Video'} Call...</p>
          <button onClick={acceptCall} style={{ ...btnStyle, background: '#4CAF50' }}>Accept</button>
          <button onClick={() => setIncomingCall(null)} style={{ ...btnStyle, background: '#f44336' }}>Decline</button>
        </div>
      )}

      {/* Video Windows */}
      {callActive && (
        <div style={videoContainerStyle}>
          <video ref={remoteVideo} autoPlay playsInline style={remoteVideoStyle} />
          {!isAudioOnly && <video ref={localVideo} autoPlay muted playsInline style={localVideoStyle} />}
          {isAudioOnly && <div style={localVideoStyle}>Audio Active</div>}
        </div>
      )}

      {/* Input Area */}
      <div style={{ padding: '15px', borderTop: '1px solid #eee' }}>
        <div style={{ display: 'flex', gap: '10px' }}>
          <input 
            value={input} 
            onChange={(e) => setInput(e.target.value)} 
            onKeyDown={(e) => e.key === 'Enter' && sendMessage()}
            placeholder="Type a message..." 
            style={{ flex: 1, padding: '10px', borderRadius: '20px', border: '1px solid #ddd' }}
          />
          <button onClick={sendMessage} style={{ ...btnStyle, borderRadius: '20px' }}>Send</button>
        </div>
      </div>
    </div>
  );
}

// Basic Styles
const btnStyle = { padding: '8px 16px', borderRadius: '4px', border: 'none', background: '#0084ff', color: '#fff', cursor: 'pointer' };
